  private Log logger = LogFactory.getLog("rule.Collibra.RequestHandler");

  Link getLinkByPrimaryEmail(String primaryEmail) {
    Filter filter = Filter.and(Filter.eq("displayName", primaryEmail), Filter.eq("application.name","GSuite"));
    return context.getUniqueObject(Link.class, filter);

  }
  int getCountOfAccounts(String primaryEmail){
    Filter filter = Filter.and(Filter.eq("displayName", primaryEmail), Filter.eq("application.name","GSuite"));
    QueryOptions qops=new QueryOptions();
    qops.addFilter(filter);
    int totalLinks = context.countObjects(Link.class,qops);
    return totalLinks;
  }

  List getRequiredVariables(Workflow workflow) {

    List<Variable> vars = workflow.getVariableDefinitions();
    List requiredVars = new ArrayList();

    for (Variable var : vars) {

      if (var.isInput()) { //If variables are marked Required within the workflow, the LaunchedWorkflows API will not throw an error when one is missing. To mitigate this behavior, marking such variables as Input has been done instead.

        requiredVars.add(var.getName());

      }

    }
    log.error("COLLIBRA REQ PARAM LIST: "+requiredVars);
    return requiredVars;

  }

  String getValidationMessage(SailPointContext context, Workflow workflow, List requiredParameters){
    String errorMsg = null;

    for (String requiredParameter : requiredParameters) {

      String prefix = "Required parameter ";
      String suffix = " is missing from the payload";
      String requiredStr = prefix + requiredParameter + suffix;

      String thisParameter = workflow.get(requiredParameter);

      if (Util.isNullOrEmpty(thisParameter)) {

        errorMsg=errorMsg!=null?(errorMsg+"; "+requiredStr):requiredStr;

      }

    }
    if(requesterPrimaryEmail!=null){

      int totalLinks = getCountOfAccounts(requesterPrimaryEmail);
      if(totalLinks==0){
        errorMsg=errorMsg!=null?(errorMsg+"; "+"The requesterPrimaryEmail: "+ requesterPrimaryEmail +" is not available in Ascension Access Management (IdentityIQ); Contact Identity Governance for assistance"):"The requesterPrimaryEmail: "+ requesterPrimaryEmail +" is not available in Ascension Access Management (IdentityIQ); Contact Identity Governance for assistance";
      }
      if(totalLinks>1){
        errorMsg=errorMsg!=null?(errorMsg+"; "+"Multiple Identities are matching with provided requesterPrimaryEmail: "+requesterPrimaryEmail+" in Ascension Access Management (IdentityIQ); Contact Identity Governance for assistance"):"Multiple Identities are matching with provided requesterPrimaryEmail: "+requesterPrimaryEmail+" in Ascension Access Management (IdentityIQ); Contact Identity Governance for assistance";
      }

    }
    if(groupOwner!=null){

      int totalLinks = getCountOfAccounts(groupOwner);
      if(totalLinks==0){
        errorMsg=errorMsg!=null?(errorMsg+"; "+"The groupOwner: "+ groupOwner +" is not available in Ascension Access Management (IdentityIQ); Contact Identity Governance for assistance"):"The groupOwner: "+ groupOwner +" is not available in Ascension Access Management (IdentityIQ); Contact Identity Governance for assistance";
      }
      if(totalLinks>1){
        errorMsg=errorMsg!=null?(errorMsg+"; "+"Multiple Identities are matching with provided groupOwner: "+groupOwner+" in Ascension Access Management (IdentityIQ); Contact Identity Governance for assistance"):"Multiple Identities are matching with provided groupOwner: "+groupOwner+" in Ascension Access Management (IdentityIQ); Contact Identity Governance for assistance";
      }

    }
    return errorMsg;
  }

  ProvisioningPlan buildPlan(SailPointContext context, Workflow workflow){	
    String requesterPrimaryEmail=workflow.get("requesterPrimaryEmail");
    ProvisioningPlan plan = new ProvisioningPlan();
    Link link = null;
    if(getCountOfAccounts(requesterPrimaryEmail) == 1){
      link = getLinkByPrimaryEmail(requesterPrimaryEmail);
    }
    if (link != null) {
      Identity identity = link.getIdentity();
      if (identity != null) {
        String identityName = identity.getName();
        workflow.put("identityName",identityName);
        plan.setIdentity(identity);
        AccountRequest accountReq = new AccountRequest();
        accountReq.setOperation(AccountRequest.Operation.Modify);
        accountReq.setNativeIdentity(link.getNativeIdentity());
        accountReq.setApplication("GSuite");
        AttributeRequest attributeReq = new AttributeRequest("Groups", groupPrimaryEmail);
        attributeReq.setOp(ProvisioningPlan.Operation.Add);
        accountReq.add(attributeReq);
        List accountReqList = new ArrayList();
        accountReqList.add(accountReq);
        plan.setAccountRequests(accountReqList);
        plan.setIdentity(identity);
      }
    }
    return plan;	
  }

  void createAudit(SailPointContext context, Workflow workflow){
    ProvisioningPlan plan=workflow.get("plan");
    if (plan != null) {
      // Record Plan via AuditEvent
      AuditEvent auditEvent = new AuditEvent();
      Attributes attrsMap = new Attributes();
      attrsMap.put("requesterPrimaryEmail", workflow.get("requesterPrimaryEmail"));
      attrsMap.put("groupPrimaryEmail", workflow.get("groupPrimaryEmail"));
      attrsMap.put("collibraGUID", workflow.get("collibraGUID"));
      attrsMap.put("collibraRequestTimestamp", workflow.get("collibraRequestTimestamp"));
      attrsMap.put("groupCorrespondingDataset", workflow.get("groupCorrespondingDataset"));
      auditEvent = new AuditEvent("Collibra Request Record", "Comment", plan.getIdentity().getName());
      auditEvent.setApplication("GSuite");
      auditEvent.setAccountName(plan.getAccountRequest("GSuite").getNativeIdentity());
      auditEvent.setAttributes(attrsMap);
      Auditor.log(auditEvent);
      context.commitTransaction();
    }	
  }

  String getMessageString(SailPointContext context, Workflow workflow){
    String msgString=null;
    List errors = new ArrayList();
    List plans = null;

    if(null != workflow.get("project")){
      plans = workflow.get("project").getPlans();
    }
    if(null != plans){
      for(ProvisioningPlan plan:plans){
        ProvisioningResult result = plan.getResult();
        if (result!=null @and result.getErrors() != null) {
          for (Message msg: result.getErrors()) {
            errors.add(msg.getMessage());
          }
        }
        if (errors.size() == 0) {
          if (plan.getAccountRequests() != null) {
            for (AccountRequest request: plan.getAccountRequests()) {
              result = request.getResult();
              if(result!=null @and result.getErrors() != null) {
                for (Message msg: result.getErrors()) {
                  errors.add(msg.getMessage());
                }
              }
            }
          }
        }
      }
    }
    log.debug("310 Append Success Message errors******"+errors);
    if (errors.size() == 0) {
      IdentityRequest idenReq=context.getObjectByName(IdentityRequest.class,identityRequestId);
      if(idenReq!=null @and idenReq.getAttribute("messages")!=null){
        List ers=idenReq.getAttribute("messages");
        for (Message msg: ers) {
          errors.add(msg.getMessage());
        }
      }
    }
    log.debug("Append Success Message errors******"+errors);
    if (errors.size() > 0) {
      msgString = "FAILURE: "+Util.listToCsv(errors);
    }else{							  
      msgString="SUCCESS: An automated Access Request has been created to add " + requesterPrimaryEmail + " to " + groupPrimaryEmail + ".";
    }
    log.debug("Append Success Message msgString******"+msgString);		
    return msgString;
  }
  public Workflow getModifiedWorkflow(Workflow workflow, String variableName, String incomingValue) throws GeneralException {

    if (Util.isNotNullOrEmpty(incomingValue)) {

      incomingValue = incomingValue.replaceAll("@.*", ""); //Trim domain suffix from incoming entitlement value

      Filter andFilter = Filter.and(Filter.eq("application.name", "GSuite"),Filter.ignoreCase(Filter.eq("displayName", incomingValue)));

      ManagedAttribute ma = context.getUniqueObject(ManagedAttribute.class, andFilter);

      if (ma != null) {
        workflow.put(variableName, ma.getValue());
      }

    }
    return workflow;
  }

  private Identity createWorkgroupForCollibra(String groupName) {

    import sailpoint.object.Identity;
    import sailpoint.tools.Util;

    Identity workgroup = new Identity();

    if (workgroup != null && Util.isNotNullOrEmpty(groupName)) {

      workgroup.setWorkgroup(true);
      workgroup.setName(groupName);
      workgroup.setDisplayName(groupName);
      workgroup.setDescription("Owners of related GSuite Group");
      workgroup.setNotificationOption(Identity.WorkgroupNotificationOption.Both);

      context.saveObject(workgroup);
      context.commitTransaction();

    }

    if (workgroup.isWorkgroup()) {

      return workgroup;

    }

  }

  private void populateCollibraWorkgroup(String groupOwner, Identity workgroup, String groupName) {

    import sailpoint.object.Filter;
    import sailpoint.object.Identity;
    import sailpoint.tools.Util;

    if (workgroup.isWorkgroup() && Util.nullSafeCaseInsensitiveEq(workgroup.getName(), groupName)) {

      Filter filter = Filter.ignoreCase(Filter.eq("email", groupOwner));
      Identity ownerIdentity = context.getUniqueObject(Identity.class, filter);

      if (ownerIdentity != null) {

        ownerIdentity.add(workgroup);

        context.saveObject(ownerIdentity);
        context.commitTransaction();

      }

    }

  }

  private void updateCollibraManagedAttribute(String groupName, String groupDescription) {

    import sailpoint.api.ManagedAttributer;
    import sailpoint.object.Application;
    import sailpoint.object.Identity;
    import sailpoint.object.ManagedAttribute;
    import sailpoint.tools.Util;

    Application app = context.getObjectByName(Application.class, "GSuite");
    Identity workgroup = context.getObjectByName(Identity.class, groupName);
    ManagedAttributer managedAttributer = new ManagedAttributer(context);

    if (app != null && managedAttributer != null && workgroup != null) {

      ManagedAttribute ma = managedAttributer.getByDisplayName(context, app, groupName);

      if (ma != null) {

        ma.setOwner(workgroup);

        if (Util.isNotNullOrEmpty(groupDescription)) {

          ma.addDescription("en_US", groupDescription);

        }

        context.saveObject(ma);
        context.commitTransaction();

      }

    }

  }

  private String getCloudGroup(String groupName) {

    try {

      token = context.decrypt(jobj); //Passed in via global variable (Rule-GSuite-AccessToken).

      String urlStr = "https://cloudidentity.googleapis.com/v1/groups/" + groupName;

      URL url = new URL(urlStr);

      HttpURLConnection conn = (HttpURLConnection) url.openConnection();
      conn.setDoOutput(true);
      conn.setRequestMethod("GET");
      conn.setRequestProperty("Content-Type", "application/json");
      conn.setRequestProperty("Authorization", "Bearer "+ token);

      BufferedReader br = new BufferedReader(new InputStreamReader(conn.getInputStream()));
      String output = "";
      String lineOutput = "";


      while ((lineOutput = br.readLine()) != null) {
        output = output + lineOutput;
      } 

      if (output != null) {

        apiResponse = output;

      }


    } catch (FileNotFoundException e) {

      throw e;
      apiResponse = "FileNotFoundException";

    } catch (java.io.IOException e) {

      apiResponse = "IOException";

    }     

    return apiResponse;

  }


