  private String aggregate(Application appObject, ResourceObject rObj) {
    Attributes argMap = new Attributes();  
    argMap.put("checkDeleted", "true");

    Aggregator agg = new Aggregator(context, argMap);  
    if (null == agg) {  
      errorMessage = "Null Aggregator returned from constructor.  Unable to Aggregate!";  
      logger.error(errorMessage);  
      return errorMessage;  
    }

    // Invoke the aggregation task by calling the aggregate() method.  
    // Note: the aggregateGroup() call may take several seconds to complete.  
    logger.debug("Calling aggregate() method... ");  
    ManagedAttribute ma = null;
    try {
      ma = agg.aggregateGroup(appObject, rObj);
    } catch (GeneralException e) {
      e.printStackTrace();
    }
    logger.debug("aggregation complete.");  

    if (null == ma) {  
      errorMessage = "ERROR: Null ManagedAttribute returned from aggregate() call.";  
      logger.error(errorMessage);  
      return errorMessage;  
    }

    try {
      logger.debug("ManagedAttribute details: \n" + ma.toXml());
    } catch (GeneralException e) {
      e.printStackTrace();
    }

    return ("Success");
  }

  private String aggregateGroup(String objectId, String applicationName) {
    String errorMessage = "";
    ResourceObject rObj = null;
    Application appObject = null;
    Connector appConnector = null;

    try {  
      appObject = context.getObjectByName(Application.class, applicationName);  
      String appConnName = appObject.getConnector();  
      logger.debug("Application " + applicationName + " uses connector " + appConnName);  

      appConnector = sailpoint.connector.ConnectorFactory.getConnector(appObject, null);  
      if (null == appConnector) {  
        errorMessage = "Failed to construct an instance of connector [" + appConnName + "]";  
        return errorMessage;  
      }

      logger.debug("Connector instantiated, calling getObject() to read account details...");  
      logger.debug("Getting Resource Object for with identity....." + objectId);  
      rObj = (ResourceObject) appConnector.getObject("group",objectId,null);

    } catch (ConnectorException onfe) {  
      errorMessage = "Connector could not find group: [" + objectId + "]";  
      errorMessage += " in application  [" + applicationName + "]";  
      logger.error(errorMessage);
      logger.error(onfe);
      return errorMessage;
    } catch (GeneralException e) {
      e.printStackTrace();
    }

    if (null == rObj) {  
      errorMessage = "ERROR: Could not get ResourceObject for group: " + objectId;  
      logger.error(errorMessage);  
      return errorMessage;  
    }  

    try {
      logger.debug("Got raw resourceObject: " + rObj.toXml());
    } catch (GeneralException e) {
      e.printStackTrace();
    }

    Rule customizationRule = appObject.getCustomizationRule("group");  
    if (null != customizationRule) {  

      logger.debug("Customization rule found for application " + applicationName);     

      try {  

        // Pass the mandatory arguments to the Customization rule for the app.  
        HashMap ruleArgs = new HashMap();  
        ruleArgs.put("context",     context);  
        ruleArgs.put("log",         logger);  
        ruleArgs.put("object",      rObj);  
        ruleArgs.put("application", appObject);  
        ruleArgs.put("connector",   appConnector);  
        ruleArgs.put("state",       new HashMap());  

        // Call the customization rule just like a normal aggregation would.  
        ResourceObject newRObj = (ResourceObject) context.runRule(customizationRule, ruleArgs, null);  

        // Make sure we got a valid resourceObject back from the rule.    
        if (null != newRObj) {  
          rObj = newRObj;  
          logger.debug("Got post-customization resourceObject: " + rObj.toXml());  
        }      

      } catch (Exception ex) {  

        // Swallow any customization rule errors, the show must go on!  
        logger.error("Error while running Customization rule for " + applicationName);  

      }  

    } 
    aggregate(appObject, rObj);  

    return rObj.toXml();
  }
